#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int cntPos = 0, cntNeg = 0, x;
        for (int i = 0; i < N; ++i) {
            scanf("%d", &x);
            if (x == 1) cntPos++; else cntNeg++;
        }
        if (cntPos > 0 && cntNeg > 0) printf("Yes\n");
        else printf("No\n");
    }
    return 0;
}

